command.text:

if @@admin <> 1 begin
  if not exists(select 1 from sysunitrights where user_id = @@userID and ma_dvcs = @ma_dvcs and r_new = 1) begin
    select '$NotAuthorized' as message
    return
  end
end

        &CommandCheckLockedDate;
        &CheckData;
        &CommandGetIdentityNumber;

select @so_ct = space(datalength(@so_ct) - len(rtrim(@so_ct))) + rtrim(@so_ct), @ma_ct = @@id, @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID


declare @ngay_ct smalldatetime
select @ngay_ct = ngay_ct from gpbdc where stt_rec = @stt_rec

        &CommandToolSupplyLockedBeforeDelete;
        &CommandWhenToolSupplyExternalBeforeDelete;

        /* <flatten type="Javascript"> */
var f = this;
if (f.getItemValue('so_luong') < 0) {
  var id = f.get_id(), o = f.getItem('so_luong');
  f._checked = false;
  $func.hideWait(id);
  $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), o.field.Label), String.format('$find(\'{0}\').focus(\'{1}\');', id, 'so_luong'));
}
/* </flatten> */

script.text:
      /* <flatten type="Javascript"> */
function loadingFormDisposal(f) {
  f.add_onResponseComplete(on$TSDisposal$ResponseComplete);
  f.$a = {
    gt_pb: '[gt_pb]:=[gt_pb1]*[so_luong]',
    gt_pb_nt: '[gt_pb_nt]:=[gt_pb_nt1]*[so_luong]',
    gt_pb0: '[gt_pb]:=[gt_pb0]*[so_luong]',
    gt_pb_nt0: '[gt_pb_nt]:=[gt_pb_nt0]*[so_luong]',

    nguyen_gia: '[nguyen_gia]:=[nguyen_gia1]*[so_luong]',
    nguyen_gia_nt: '[nguyen_gia_nt]:=[nguyen_gia_nt1]*[so_luong]',
    nguyen_gia0: '[nguyen_gia]:=[nguyen_gia0]*[so_luong]',
    nguyen_gia_nt0: '[nguyen_gia_nt]:=[nguyen_gia_nt0]*[so_luong]'
  };
}
function initFormDisposal(f) {
  if (f._action != 'View') f._setReadOnly(f.getItem('ma_dc'), f._action == 'Edit' && !f.getItemValue('dv_yn'));
  switch (f._action) {
    case 'New':
      f.setItemValues('nguyen_gia_nt1, nguyen_gia1, gt_pb_nt1, gt_pb1', [0, 0, 0, 0]);
      break;
  }
  onChange$AllocatedValue(f);
}
function close$TSDisposal$(f) {try {f.remove_onResponseComplete(on$TSDisposal$ResponseComplete);} catch (ex) {}}
function onChange$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_bp_dc':
    case 'ma_dc':
      f.request('TSCode', 'TSCode', ['ma_dc', 'ngay_ct', 'ma_bp_dc', 'stt_rec', 'kieu_pb']);
      break;
    case 'ngay_ct':
      f.request('TSCode', 'DereaseQty', ['ma_dc', 'ngay_ct', 'ma_bp_dc', 'stt_rec', 'kieu_pb']);
      break;
    case 'kieu_pb':
    case 'so_luong':
      calcAllocatedValue(f);
      break;
    case 'sua_gt_pb':
      onChange$AllocatedValue(f, true);
      break;
    default:
      break;
  }
}

function on$TSDisposal$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'TSCode':
      f.setItemValues('ma_dvcs, nguyen_gia_nt1, nguyen_gia1, gt_pb_nt1, gt_pb1', [$func.trim(result[0].Value), result[1].Value, result[2].Value, result[3].Value, result[4].Value]);
      f.setItemValues('nguyen_gia_nt0, nguyen_gia0, gt_pb_nt0, gt_pb0', [result[7].Value, result[8].Value, result[9].Value, result[10].Value]);
      f.setItemControlBehavior('ma_nt', $func.trim(result[5].Value), result[6].Value, true);
      f.setReferenceKeyFilter('ma_bp_dc');
      setValueTSCode(f, result);
      calcAllocatedValue(f);
      break;
    case 'DereaseQty':
      f.setItemValues('nguyen_gia_nt0, nguyen_gia0, gt_pb_nt0, gt_pb0', [result[7].Value, result[8].Value, result[9].Value, result[10].Value]);
      setValueTSCode(f, result);
      calcAllocatedValue(f);
      break;
    default:
      break;
  }
}
function calcAllocatedValue(f) {
  if (f.getItemValue('so_luong') <= 0 || f.getItemValue('ma_dc') == '') {
    f.setItemValues('nguyen_gia_nt, nguyen_gia, gt_pb_nt, gt_pb', [0, 0, 0, 0]);
    return;
  }
  if (f.getItemValue('kieu_pb') == 1) f.executeExpression([f.$a.gt_pb, f.$a.gt_pb_nt, f.$a.nguyen_gia, f.$a.nguyen_gia_nt]);
    else {
      if (f._quantity == f.getItemValue('so_luong')) {
          f.setItemValues('gt_pb_nt, gt_pb', [f._gt_nt, f._gt]);
          f.executeExpression([f.$a.nguyen_gia0, f.$a.nguyen_gia_nt0]);
        }
        else
          f.executeExpression([f.$a.gt_pb0, f.$a.gt_pb_nt0, f.$a.nguyen_gia0, f.$a.nguyen_gia_nt0]);
    }
}
function onChange$AllocatedValue(f, force) {window.setTimeout(String.format('onFocus$AllocatedValue(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$AllocatedValue(id, force) {
  var f = $find(id);
  var c = (f.getItemValue('ma_nt') == f._baseCurrency), e = (f.getItemValue('sua_gt_pb') == '0');
  var t1 = f.getItem('gt_pb_nt'), t2 = f.getItem('gt_pb'), t3 = f.getItem('dien_giai');
  if (force) setItemLive(c? t2 : t1 , t3, !e);
  setItemDisable(f, 'gt_pb_nt', (c || e));
  setItemDisable(f, 'gt_pb', e);
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    o.disabled = v;
  }
}
function setItemLive(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus();}}
    else {if (t1.live) {t2.disabled = false; t2.focus();}}
}

function setValueTSCode (f, r) {
  f._gt_nt = r[11].Value;
  f._gt = r[12].Value;
  f._quantity = r[13].Value;
}
/* </flatten> */
